impl<R: NotificationTemplateProjectionRepository> NotificationTemplateEventHandler for NotificationTemplateProjector<R> {

    async fn on_created(&self, event: NotificationTemplateCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = NotificationTemplateProjection::new(
            event.id,
            event.name,
            event.notification_type,
            event.channel,
            event.subject_template,
            event.message_template,
            event.variables,
            event.is_active,
            event.language,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: NotificationTemplateUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.name = event.name;
            projection.notification_type = event.notification_type;
            projection.channel = event.channel;
            projection.subject_template = event.subject_template;
            projection.message_template = event.message_template;
            projection.variables = event.variables;
            projection.is_active = event.is_active;
            projection.language = event.language;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: NotificationTemplateDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

